using Microsoft.VisualStudio.TestTools.UnitTesting;
using Payments;

namespace Payments.Tests;

[TestClass]
public class ChargeTests
{
    private PaymentGateway _gateway = null!;

    [TestInitialize]
    public void Setup()
    {
        _gateway = new PaymentGateway();
    }

    [TestMethod]
    public async Task ChargeAsync_ValidCardAndAmount_ReturnsSuccess()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 49.99m);

        Assert.IsTrue(result.Success);
        Assert.IsFalse(string.IsNullOrWhiteSpace(result.ChargeId));
    }

    [TestMethod]
    public async Task ChargeAsync_DifferentAmounts_EachReturnsUniqueChargeId()
    {
        var result1 = await _gateway.ChargeAsync("tok_valid_visa", 10.00m);
        var result2 = await _gateway.ChargeAsync("tok_valid_visa", 20.00m);

        Assert.AreNotEqual(result1.ChargeId, result2.ChargeId);
    }

    [TestMethod]
    [DataRow("")]
    [DataRow("   ")]
    public async Task ChargeAsync_EmptyOrWhitespaceToken_ThrowsArgumentException(string token)
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.ChargeAsync(token, 10.00m));
    }

    [TestMethod]
    public async Task ChargeAsync_NullToken_ThrowsArgumentNullException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentNullException>(
            () => _gateway.ChargeAsync(null!, 10.00m));
    }

    [TestMethod]
    public async Task ChargeAsync_ZeroAmount_ThrowsArgumentOutOfRangeException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentOutOfRangeException>(
            () => _gateway.ChargeAsync("tok_valid_visa", 0m));
    }

    [TestMethod]
    public async Task ChargeAsync_NegativeAmount_ThrowsArgumentOutOfRangeException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentOutOfRangeException>(
            () => _gateway.ChargeAsync("tok_valid_visa", -5.00m));
    }

    [TestMethod]
    public async Task ChargeAsync_DeclinedCard_ReturnsFailure()
    {
        var result = await _gateway.ChargeAsync("tok_declined", 25.00m);

        Assert.IsFalse(result.Success);
        Assert.IsFalse(string.IsNullOrWhiteSpace(result.ChargeId));
    }

    [TestMethod]
    public async Task ChargeAsync_VeryLargeAmount_ReturnsSuccess()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 999_999.99m);

        Assert.IsTrue(result.Success);
    }

    [TestMethod]
    public async Task ChargeAsync_SmallestValidAmount_ReturnsSuccess()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 0.01m);

        Assert.IsTrue(result.Success);
    }
}

[TestClass]
public class RefundTests
{
    private PaymentGateway _gateway = null!;

    [TestInitialize]
    public void Setup()
    {
        _gateway = new PaymentGateway();
    }

    [TestMethod]
    public async Task RefundAsync_ValidChargeId_ReturnsSuccess()
    {
        var charge = await _gateway.ChargeAsync("tok_valid_visa", 50.00m);

        var refund = await _gateway.RefundAsync(charge.ChargeId);

        Assert.IsTrue(refund.Success);
        Assert.IsFalse(string.IsNullOrWhiteSpace(refund.RefundId));
    }

    [TestMethod]
    public async Task RefundAsync_NullChargeId_ThrowsArgumentNullException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentNullException>(
            () => _gateway.RefundAsync(null!));
    }

    [TestMethod]
    [DataRow("")]
    [DataRow("   ")]
    public async Task RefundAsync_EmptyOrWhitespaceChargeId_ThrowsArgumentException(string chargeId)
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.RefundAsync(chargeId));
    }

    [TestMethod]
    public async Task RefundAsync_NonexistentChargeId_ReturnsFailure()
    {
        var result = await _gateway.RefundAsync("ch_does_not_exist");

        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    public async Task RefundAsync_AlreadyRefundedCharge_ReturnsFailure()
    {
        var charge = await _gateway.ChargeAsync("tok_valid_visa", 30.00m);
        await _gateway.RefundAsync(charge.ChargeId);

        var secondRefund = await _gateway.RefundAsync(charge.ChargeId);

        Assert.IsFalse(secondRefund.Success);
    }

    [TestMethod]
    public async Task RefundAsync_MultipleCharges_RefundCorrectOne()
    {
        var charge1 = await _gateway.ChargeAsync("tok_valid_visa", 10.00m);
        var charge2 = await _gateway.ChargeAsync("tok_valid_visa", 20.00m);

        var refund = await _gateway.RefundAsync(charge1.ChargeId);

        Assert.IsTrue(refund.Success);

        // Second charge should still be refundable
        var refund2 = await _gateway.RefundAsync(charge2.ChargeId);
        Assert.IsTrue(refund2.Success);
    }
}

